          __m512d Ti=_mm512_fmadd_pd(c1,d1i,_mm512_mul_pd(c2,d2i)), Tu=_mm512_fmadd_pd(c1,d1r,_mm512_mul_pd(c2,d2r));
          __m512d Tk=_mm512_fnmadd_pd(c2,d1i,_mm512_mul_pd(c1,d2i)), Tv=_mm512_fnmadd_pd(c2,d1r,_mm512_mul_pd(c1,d2r));
          x0_re=_mm512_add_pd(x0_re,_mm512_add_pd(s1r,s2r)); x0_im=_mm512_add_pd(x0_im,_mm512_add_pd(s1i,s2i));
          x1_re=_mm512_sub_pd(p1r,Ti); x1_im=_mm512_add_pd(p1i,Tu);
